import { revalidateTag, unstable_cache } from 'next/cache';

type Product = {
  id: number;
  sku: string;
  name: string;
  price: number;
  inventory: number;
  availability: 'In stock' | 'Low stock' | 'Backorder';
  updatedAt: string;
};

let products: Product[] = [
  {
    id: 1,
    sku: 'LTP-001',
    name: 'Laptop Pro 14',
    price: 1299,
    inventory: 18,
    availability: 'In stock',
    updatedAt: '2026-07-07T09:00:00.000Z'
  },
  {
    id: 2,
    sku: 'PHN-002',
    name: 'Phone Max',
    price: 899,
    inventory: 42,
    availability: 'In stock',
    updatedAt: '2026-07-07T09:00:00.000Z'
  },
  {
    id: 3,
    sku: 'TAB-003',
    name: 'Tablet Air',
    price: 649,
    inventory: 7,
    availability: 'Low stock',
    updatedAt: '2026-07-07T09:00:00.000Z'
  },
  {
    id: 4,
    sku: 'AUD-004',
    name: 'Noise Canceling Headphones',
    price: 249,
    inventory: 0,
    availability: 'Backorder',
    updatedAt: '2026-07-07T09:00:00.000Z'
  },
  {
    id: 5,
    sku: 'WRB-005',
    name: 'Smart Watch',
    price: 329,
    inventory: 23,
    availability: 'In stock',
    updatedAt: '2026-07-07T09:00:00.000Z'
  }
];

async function fetchProductsFromSource() {
  await new Promise((resolve) => setTimeout(resolve, 150));
  return structuredClone(products);
}

export const getAllProducts = unstable_cache(fetchProductsFromSource, ['products-catalog'], {
  tags: ['products']
});

export type { Product };

export async function syncLatestCatalog() {
  setTimeout(async () => {
    const timestamp = new Date().toISOString();

    products = products.map((product, index) => {
      const inventory = Math.max(0, product.inventory + ((index % 3) - 1) * 4 + 2);
      const price = product.price + (index % 2 === 0 ? 15 : -10);

      return {
        ...product,
        price,
        inventory,
        availability: inventory === 0 ? 'Backorder' : inventory < 10 ? 'Low stock' : 'In stock',
        updatedAt: timestamp
      };
    });

    revalidateTag('products', 'max');
  }, 0);
}

import { syncLatestCatalog, getAllProducts } from '@/lib/db';

const currency = new Intl.NumberFormat('en-US', {
  style: 'currency',
  currency: 'USD'
});

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ fontFamily: 'Arial, sans-serif', padding: '32px', maxWidth: '1100px', margin: '0 auto' }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: '24px',
          marginBottom: '24px'
        }}
      >
        <div>
          <p style={{ margin: 0, color: '#666', textTransform: 'uppercase', letterSpacing: '0.08em' }}>
            Admin catalog
          </p>
          <h1 style={{ margin: '8px 0 12px', fontSize: '2rem' }}>Product catalog</h1>
          <p style={{ margin: 0, maxWidth: '700px', color: '#444', lineHeight: 1.5 }}>
            Browse a cached catalog for fast day-to-day operations. When ERP or PIM data changes, trigger a
            background sync to refresh all catalog views tagged with <code>products</code> shortly after.
          </p>
        </div>

        <form
          action={async () => {
            'use server';
            await syncLatestCatalog();
          }}
        >
          <button
            type="submit"
            style={{
              border: 'none',
              borderRadius: '10px',
              background: '#111827',
              color: '#fff',
              padding: '12px 18px',
              cursor: 'pointer',
              fontWeight: 600
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <div
        style={{
          padding: '16px',
          marginBottom: '18px',
          background: '#f3f4f6',
          border: '1px solid #e5e7eb',
          borderRadius: '12px',
          color: '#374151'
        }}
      >
        Sync runs asynchronously so admins can keep working immediately while stale catalog data is refreshed in
        the background.
      </div>

      <div style={{ overflowX: 'auto', border: '1px solid #e5e7eb', borderRadius: '12px' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              <th style={headerCellStyle}>SKU</th>
              <th style={headerCellStyle}>Product</th>
              <th style={headerCellStyle}>Price</th>
              <th style={headerCellStyle}>Inventory</th>
              <th style={headerCellStyle}>Availability</th>
              <th style={headerCellStyle}>Last updated</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderTop: '1px solid #e5e7eb' }}>
                <td style={bodyCellStyle}>{product.sku}</td>
                <td style={bodyCellStyle}>{product.name}</td>
                <td style={bodyCellStyle}>{currency.format(product.price)}</td>
                <td style={bodyCellStyle}>{product.inventory}</td>
                <td style={bodyCellStyle}>
                  <span style={getAvailabilityBadgeStyle(product.availability)}>{product.availability}</span>
                </td>
                <td style={bodyCellStyle}>{new Date(product.updatedAt).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}

const headerCellStyle = {
  textAlign: 'left' as const,
  padding: '14px 16px',
  fontSize: '0.85rem',
  color: '#6b7280',
  letterSpacing: '0.04em',
  textTransform: 'uppercase' as const
};

const bodyCellStyle = {
  padding: '16px',
  color: '#111827'
};

function getAvailabilityBadgeStyle(availability: string) {
  if (availability === 'Backorder') {
    return badgeStyle('#fee2e2', '#991b1b');
  }

  if (availability === 'Low stock') {
    return badgeStyle('#fef3c7', '#92400e');
  }

  return badgeStyle('#dcfce7', '#166534');
}

function badgeStyle(background: string, color: string) {
  return {
    display: 'inline-block',
    padding: '4px 10px',
    borderRadius: '999px',
    background,
    color,
    fontWeight: 600,
    fontSize: '0.85rem'
  };
}

